import type * as DMMF from '@prisma/dmmf'

import { prismaTypeToTs } from './prisma-type-to-ts'

/**
 * Derives the plural, lowercase REST path segment for a model.
 * e.g. "User" → "users", "Category" → "categorys" (intentionally simple –
 * callers can override via generator config if needed).
 */
export function modelNameToPath(modelName: string): string {
  const lower = `${modelName.charAt(0).toLowerCase()}${modelName.slice(1)}`
  // Append 's' unless the name already ends in 's'.
  return lower.endsWith('s') ? lower : `${lower}s`
}

/** Returns `true` for fields whose value is produced automatically by the DB
 *  or Prisma (autoincrement, cuid, uuid, now, @updatedAt, …) and therefore
 *  must be omitted from `CreateInput`. */
function isAutoGenerated(field: DMMF.Field): boolean {
  if (field.isUpdatedAt) return true
  if (!field.hasDefaultValue || field.default === undefined) return false
  const def = field.default
  // FieldDefault = { name: string; args: Array<string | number> }
  if (typeof def === 'object' && !Array.isArray(def) && 'name' in def) {
    const name = (def as { name: string }).name
    return ['autoincrement', 'cuid', 'uuid', 'now', 'dbgenerated', 'sequence', 'auto'].includes(name)
  }
  return false
}

/** Returns `true` for scalar and enum fields (i.e. not object/relation fields). */
function isDataField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

function tsFieldType(field: DMMF.Field): string {
  return `${prismaTypeToTs(field.type)}${field.isList ? '[]' : ''}`
}

/**
 * Generates all TypeScript source declarations for one Prisma model:
 *
 * - `ModelName` interface (full record shape)
 * - `ModelNameWhereUniqueInput` (id/unique fields, all optional)
 * - `ModelNameWhereInput` (all scalar fields, all optional)
 * - `ModelNameCreateInput` (writable scalar fields, required unless optional/defaulted)
 * - `ModelNameUpdateInput` (all non-id scalar fields, all optional)
 * - `ModelNameClient` class with `findMany`, `findUnique`, `create`, `update`, `delete`
 */
export function generateModelCode(model: DMMF.Model): string {
  const { name } = model
  const path = modelNameToPath(name)
  const lines: string[] = []

  // ── Full record interface ────────────────────────────────────────────────
  lines.push(`export interface ${name} {`)
  for (const field of model.fields) {
    if (field.kind === 'unsupported') continue
    const type = tsFieldType(field)
    const optional = !field.isRequired ? '?' : ''
    const nullUnion = !field.isRequired && !field.isList ? ' | null' : ''
    lines.push(`  ${field.name}${optional}: ${type}${nullUnion}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── WhereUniqueInput ─────────────────────────────────────────────────────
  const uniqueFields = model.fields.filter((f) => isDataField(f) && (f.isId || f.isUnique))
  lines.push(`export interface ${name}WhereUniqueInput {`)
  for (const field of uniqueFields) {
    lines.push(`  ${field.name}?: ${tsFieldType(field)}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── WhereInput ───────────────────────────────────────────────────────────
  lines.push(`export interface ${name}WhereInput {`)
  for (const field of model.fields) {
    if (!isDataField(field)) continue
    lines.push(`  ${field.name}?: ${tsFieldType(field)}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── CreateInput ──────────────────────────────────────────────────────────
  // Exclude id fields and auto-generated fields; mark the rest optional if
  // they have a non-auto default or are already optional.
  const createFields = model.fields.filter((f) => isDataField(f) && !f.isId && !isAutoGenerated(f))
  lines.push(`export interface ${name}CreateInput {`)
  for (const field of createFields) {
    const optional = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsFieldType(field)}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── UpdateInput ──────────────────────────────────────────────────────────
  const updateFields = model.fields.filter((f) => isDataField(f) && !f.isId)
  lines.push(`export interface ${name}UpdateInput {`)
  for (const field of updateFields) {
    lines.push(`  ${field.name}?: ${tsFieldType(field)}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── Client class ─────────────────────────────────────────────────────────
  lines.push(`export class ${name}Client {`)
  lines.push(`  constructor(private readonly baseUrl: string) {}`)
  lines.push(``)

  // findMany
  lines.push(`  async findMany(params?: { where?: ${name}WhereInput }): Promise<${name}[]> {`)
  lines.push(`    const url = new URL(\`\${this.baseUrl}/${path}\`)`)
  lines.push(`    if (params?.where) {`)
  lines.push(`      url.searchParams.set('where', JSON.stringify(params.where))`)
  lines.push(`    }`)
  lines.push(`    const response = await fetch(url.toString())`)
  lines.push(`    if (!response.ok) throw new Error(\`Request failed with status \${response.status}\`)`)
  lines.push(`    return response.json() as Promise<${name}[]>`)
  lines.push(`  }`)
  lines.push(``)

  // findUnique
  lines.push(`  async findUnique(params: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {`)
  lines.push(`    const url = new URL(\`\${this.baseUrl}/${path}/unique\`)`)
  lines.push(`    url.searchParams.set('where', JSON.stringify(params.where))`)
  lines.push(`    const response = await fetch(url.toString())`)
  lines.push(`    if (!response.ok) throw new Error(\`Request failed with status \${response.status}\`)`)
  lines.push(`    return response.json() as Promise<${name} | null>`)
  lines.push(`  }`)
  lines.push(``)

  // create
  lines.push(`  async create(params: { data: ${name}CreateInput }): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.baseUrl}/${path}\`, {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(params.data),`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) throw new Error(\`Request failed with status \${response.status}\`)`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(``)

  // update
  lines.push(`  async update(params: { where: ${name}WhereUniqueInput; data: ${name}UpdateInput }): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.baseUrl}/${path}\`, {`)
  lines.push(`      method: 'PATCH',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(params),`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) throw new Error(\`Request failed with status \${response.status}\`)`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(``)

  // delete
  lines.push(`  async delete(params: { where: ${name}WhereUniqueInput }): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.baseUrl}/${path}\`, {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(params.where),`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) throw new Error(\`Request failed with status \${response.status}\`)`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(`}`)
  lines.push(``)

  return lines.join('\n')
}

/**
 * Generates the top-level `RestApiClient` class that exposes one typed
 * sub-client property per model.
 */
export function generateRootClientCode(modelNames: string[]): string {
  const lines: string[] = []

  lines.push(`export class RestApiClient {`)
  for (const name of modelNames) {
    const prop = `${name.charAt(0).toLowerCase()}${name.slice(1)}`
    lines.push(`  readonly ${prop}: ${name}Client`)
  }
  lines.push(``)
  lines.push(`  constructor(baseUrl: string) {`)
  for (const name of modelNames) {
    const prop = `${name.charAt(0).toLowerCase()}${name.slice(1)}`
    lines.push(`    this.${prop} = new ${name}Client(baseUrl)`)
  }
  lines.push(`  }`)
  lines.push(`}`)
  lines.push(``)

  return lines.join('\n')
