import { join } from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateModelCode, generateRootClientCode } from './model-to-code'

/** Parameters forwarded from `GeneratorOptions` that we actually need. */
export interface GenerateClientParams {
  outputDir: string
  models: readonly DMMF.Model[]
}

const FILE_HEADER = `\
// This file was generated by @prisma/rest-api-client-generator.
// Do not edit it manually.
// Re-generate by running \`prisma generate\`.

`

/**
 * Generates a typed REST API client from the provided DMMF models and writes
 * the result to `<outputDir>/index.ts`.
 *
 * The generated file contains:
 * - One TypeScript interface per model (full record shape)
 * - Input types: `WhereUniqueInput`, `WhereInput`, `CreateInput`, `UpdateInput`
 * - A `ModelNameClient` class with `findMany`, `findUnique`, `create`, `update`, `delete`
 * - A top-level `RestApiClient` class that composes all model clients
 */
export async function generateClient({ outputDir, models }: GenerateClientParams): Promise<void> {
  await mkdir(outputDir, { recursive: true })

  const sections: string[] = [FILE_HEADER]

  for (const model of models) {
    sections.push(generateModelCode(model))
  }

  const modelNames = models.map((m) => m.name)
  sections.push(generateRootClientCode(modelNames))

  await writeFile(join(outputDir, 'index.ts'), sections.join(''), 'utf-8')
}

