import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateClient } from './generate-client'

const DEFAULT_OUTPUT = './generated/rest-client'

function getOutputPath(config: GeneratorConfig): string {
  if (config.output) {
    return parseEnvValue(config.output)
  }
  return DEFAULT_OUTPUT
}

/**
 * Prisma generator that emits a typed REST API client from the schema's DMMF.
 *
 * Register it in a Prisma schema with:
 *
 * ```prisma
 * generator restClient {
 *   provider = "prisma-rest-api-client"
 *   output   = "../src/generated/rest-client"
 * }
 * ```
 *
 * The generator writes a single `index.ts` to the configured output directory
 * containing TypeScript interfaces and a fetch-based client class for every
 * model in the schema.
 */
export class RestApiClientGenerator implements Generator {
  readonly name = 'prisma-rest-api-client'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST API Client',
      defaultOutput: getOutputPath(config),
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = getOutputPath(options.generator)
    const models = options.dmmf.datamodel.models

    await generateClient({ outputDir, models })
  }
}

