    expect(code).toContain('id: number')
    expect(code).toContain('email: string')
    expect(code).toContain('name?: string | null')
    expect(code).toContain('createdAt: Date')
    expect(code).toContain('role: Role')
  })

  it('emits WhereUniqueInput with id and unique fields only', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain('export interface UserWhereUniqueInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email?: string')
    expect(code).not.toMatch(/UserWhereUniqueInput \{[^}]*name\?/)
  })

  it('emits WhereInput with all scalar fields optional', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain('export interface UserWhereInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('name?: string')
    expect(code).toContain('email?: string')
  })

  it('excludes auto-generated fields from CreateInput', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain('export interface UserCreateInput {')
    // id is autoincrement → excluded
    expect(code).not.toMatch(/UserCreateInput \{[^}]*\bid\b/)
    // createdAt has @default(now()) → excluded
    expect(code).not.toMatch(/UserCreateInput \{[^}]*\bcreatedAt\b/)
    // email is required with no default → required in CreateInput
    expect(code).toMatch(/UserCreateInput \{[\s\S]*?email: string/)
  })

  it('emits UpdateInput with non-id fields all optional', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain('export interface UserUpdateInput {')
    // id must not appear
    expect(code).not.toMatch(/UserUpdateInput \{[^}]*\bid\b/)
    expect(code).toContain('email?: string')
    expect(code).toContain('name?: string')
  })

  it('emits the client class with all five CRUD methods', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain('export class UserClient {')
    expect(code).toContain('async findMany(')
    expect(code).toContain('async findUnique(')
    expect(code).toContain('async create(')
    expect(code).toContain('async update(')
    expect(code).toContain('async delete(')
  })

  it('uses the correct HTTP methods', () => {
    const code = generateModelCode(userModel as never)
    expect(code).toContain("method: 'POST'")
    expect(code).toContain("method: 'PATCH'")
    expect(code).toContain("method: 'DELETE'")
    // findMany and findUnique use GET (no method: … means the fetch default)
    expect(code).not.toContain("method: 'GET'")
  })

  it('routes findMany to the plural model path', () => {
    const code = generateModelCode(userModel as never)
    // The path for User is "users"
    expect(code).toContain('`${this.baseUrl}/users`')
  })

  it('skips unsupported fields', () => {
    const modelWithUnsupported = {
      ...userModel,
      fields: [
        ...userModel.fields,
        makeField({ name: 'geo', type: 'Unsupported', kind: 'unsupported' as const }),
      ],
    }
    const code = generateModelCode(modelWithUnsupported as never)
    expect(code).not.toContain('geo')
  })
})

// ---------------------------------------------------------------------------
// generateRootClientCode
// ---------------------------------------------------------------------------

describe('generateRootClientCode', () => {
  it('emits the RestApiClient class with one property per model', () => {
    const code = generateRootClientCode(['User', 'Post'])
    expect(code).toContain('export class RestApiClient {')
    expect(code).toContain('readonly user: UserClient')
    expect(code).toContain('readonly post: PostClient')
  })

  it('initialises each sub-client in the constructor', () => {
    const code = generateRootClientCode(['User', 'Post'])
    expect(code).toContain('this.user = new UserClient(baseUrl)')
    expect(code).toContain('this.post = new PostClient(baseUrl)')
  })

  it('produces an empty-body class for zero models', () => {
    const code = generateRootClientCode([])
    expect(code).toContain('export class RestApiClient {')
    expect(code).toContain('constructor(baseUrl: string)')
  })
})

